    const uint32_t strideD = static_cast<uint32_t>(stride_attr[0]);
    const uint32_t strideH = static_cast<uint32_t>(stride_attr[1]);
    const uint32_t strideW = static_cast<uint32_t>(stride_attr[2]);

    const uint32_t padD = static_cast<uint32_t>(padding_attr[0]);
    const uint32_t padH = static_cast<uint32_t>(padding_attr[1]);
    const uint32_t padW = static_cast<uint32_t>(padding_attr[2]);

